defmodule TodoList.Domain.Types.Priority do
  @moduledoc """
  Domain type for task priority/ordering.

  Represents the display order of tasks in the list. Lower numbers appear first.
  Must be a non-negative integer.

  ## Examples

      iex> {:ok, priority} = Priority.new(0)
      iex> Priority.value(priority)
      0

      iex> {:ok, priority} = Priority.new(42)
      iex> Priority.value(priority)
      42

      iex> Priority.new(-1)
      {:error, :priority_must_be_non_negative}

      iex> Priority.new("not a number")
      {:error, :invalid_type}
  """

  @enforce_keys [:value]
  defstruct [:value]

  @type t :: %__MODULE__{value: non_neg_integer()}

  @doc """
  Creates a new Priority from an integer.

  Must be non-negative (>= 0).

  Returns `{:ok, priority}` if valid, or `{:error, reason}` if invalid.

  ## Examples

      iex> Priority.new(0)
      {:ok, %Priority{value: 0}}

      iex> Priority.new(100)
      {:ok, %Priority{value: 100}}

      iex> Priority.new(-1)
      {:error, :priority_must_be_non_negative}

      iex> Priority.new(3.14)
      {:error, :invalid_type}
  """
  @spec new(integer()) :: {:ok, t()} | {:error, :priority_must_be_non_negative | :invalid_type}
  def new(value) when is_integer(value) and value >= 0 do
    {:ok, %__MODULE__{value: value}}
  end

  def new(value) when is_integer(value) do
    {:error, :priority_must_be_non_negative}
  end

  def new(_), do: {:error, :invalid_type}

  @doc """
  Extracts the underlying integer value from a Priority.

  ## Examples

      iex> {:ok, priority} = Priority.new(5)
      iex> Priority.value(priority)
      5
  """
  @spec value(t()) :: non_neg_integer()
  def value(%__MODULE__{value: value}), do: value
end

defimpl String.Chars, for: TodoList.Domain.Types.Priority do
  def to_string(%{value: value}), do: Integer.to_string(value)
end

defimpl Jason.Encoder, for: TodoList.Domain.Types.Priority do
  def encode(%{value: value}, opts) do
    Jason.Encode.integer(value, opts)
  end
end

defmodule TodoList.Domain.Types.Timestamp do
  @moduledoc """
  Domain type for UTC timestamps.

  Ensures all timestamps in the domain are UTC DateTimes. Prevents timezone
  confusion and ensures consistent time representation.

  ## Examples

      iex> {:ok, timestamp} = Timestamp.new(~U[2026-02-05 10:30:00Z])
      iex> Timestamp.value(timestamp)
      ~U[2026-02-05 10:30:00Z]

      iex> {:ok, timestamp} = Timestamp.utc_now()
      iex> is_struct(Timestamp.value(timestamp), DateTime)
      true

      iex> Timestamp.new("not a datetime")
      {:error, :invalid_type}
  """

  @enforce_keys [:value]
  defstruct [:value]

  @type t :: %__MODULE__{value: DateTime.t()}

  @doc """
  Creates a new Timestamp from a DateTime.

  Must be a valid UTC DateTime.

  Returns `{:ok, timestamp}` if valid, or `{:error, reason}` if invalid.

  ## Examples

      iex> Timestamp.new(~U[2026-02-05 10:30:00Z])
      {:ok, %Timestamp{value: ~U[2026-02-05 10:30:00Z]}}

      iex> Timestamp.new("not a datetime")
      {:error, :invalid_type}
  """
  @spec new(DateTime.t()) :: {:ok, t()} | {:error, :invalid_type}
  def new(%DateTime{} = value) do
    {:ok, %__MODULE__{value: value}}
  end

  def new(_), do: {:error, :invalid_type}

  @doc """
  Creates a new Timestamp representing the current UTC time.

  Always succeeds.

  ## Examples

      iex> {:ok, timestamp} = Timestamp.utc_now()
      iex> is_struct(Timestamp.value(timestamp), DateTime)
      true
  """
  @spec utc_now() :: {:ok, t()}
  def utc_now do
    {:ok, %__MODULE__{value: DateTime.utc_now()}}
  end

  @doc """
  Extracts the underlying DateTime value from a Timestamp.

  ## Examples

      iex> {:ok, timestamp} = Timestamp.new(~U[2026-02-05 10:30:00Z])
      iex> Timestamp.value(timestamp)
      ~U[2026-02-05 10:30:00Z]
  """
  @spec value(t()) :: DateTime.t()
  def value(%__MODULE__{value: value}), do: value
end

defimpl String.Chars, for: TodoList.Domain.Types.Timestamp do
  def to_string(%{value: value}), do: DateTime.to_iso8601(value)
end

defimpl Jason.Encoder, for: TodoList.Domain.Types.Timestamp do
  def encode(%{value: value}, opts) do
    Jason.Encode.string(DateTime.to_iso8601(value), opts)
  end
end

